import React from 'react';
import {Helmet} from "react-helmet";
import { Link } from "react-router-dom";
import $ from 'jquery';
import './article.scss';

class Article extends React.Component {
    static boolForUB = true;
    static loadingEl = $("#loading");

    constructor(props) {
        super(props);
        try {
            require("./pages"+window.location.pathname +"_worksheet");
            this.state = {
                footerEl: <footer style={{gridTemplateColumns:"33% 33% 33%"}}><Link to={{pathname:"/"}}>Home Page</Link><Link to={{pathname:"../contact"}}>Contact Us</Link><Link to={{pathname:"/worksheet",search:"?topic=" + window.location.pathname.slice(1)}}>Worksheet</Link></footer>
            }
        } catch (err) {
            this.state = {
                footerEl: <footer><Link to={{pathname:"/"}}>Home Page</Link><Link to={{pathname:"../contact"}}>Contact Us</Link></footer>
            }
        }
    }

    render() {
        let output = null;
        let DOMP = new DOMParser();
        let htmlDoc = DOMP.parseFromString(require("./pages"+window.location.pathname+".html").default, 'text/html');
        let titleTag = htmlDoc.getElementsByTagName("title")[0].text;
        let bodyChildrenDoc = htmlDoc.getElementsByTagName("body")[0].innerHTML;
        document.body.className = "articleBody";
        output =
        <>
            <Helmet>
                <title>{titleTag}</title>
            </Helmet>
            <div id='article'>
                <div id="notFooter" dangerouslySetInnerHTML={{__html: bodyChildrenDoc}}></div>
                {this.state.footerEl}
            </div>
        </>;
        return (output);
    }

    scrollFunc(){
        if(Article.boolForUB){
            if(window.scrollY>1000){$("#upButton").fadeIn(200);}
            else{$("#upButton").fadeOut(200);}
        }
    }

    viewImg(el){
        let cloneImg;
        $("#imgViewer").css({"width":"100%","height":"100%","background-color":"rgba(0,0,0,0.8)","padding-bottom":"20px","padding-top":"20px"});
        $("#upButton").css("display","none");
        if(el.target.tagName ==="IMG"){
            cloneImg = $(el.target).clone();
            cloneImg.removeAttr("style");
        }
        else if($(el.target).closest(".mathStuff").length>0){
            cloneImg = $($(el.target).closest(".mathStuff")[0]).clone();
        }
        $("#imgViewer").html(cloneImg);
        $("body").css("overflow","hidden");
        Article.boolForUB = false;
    }
    
    removeViewer(){
        $("#imgViewer").css({"width":"0","height":"0","padding-bottom":"0px","padding-top":"0px"});
        $("#upButton").css("display","none");
        $("#upButton").css("display","fixed");
        $("body").css("overflow","visible");
        Article.boolForUB = true;
    }

    componentDidMount() {
        let articleEl = $("#article");
        let upImg = document.createElement("img");
        upImg.setAttribute("src","/webPics/caret-up-solid.svg");
        upImg.classList.add("icon");
        let upImgCont = document.createElement("div");
        upImgCont.id = "upButton";
        upImgCont.appendChild(upImg);
        articleEl.append(upImgCont);
        articleEl.append("<div id='imgViewer'></div>");
        if(document.getElementById("sources")){
            $("#sources").before("<h4>Sources:</h4>");
            for(let sChild of document.getElementById("sources").children){
                if(sChild.className){
                    $(sChild).prepend($("<span>&nbsp;&nbsp;&nbsp;&nbsp;</span>"));
                    sChild.querySelector("span").classList.add(sChild.className);
                    sChild.classList.remove(sChild.className);
                };
            }
        }
        $(".content a").each(function(){$(this).attr("target","_blank");});
        $('.content ol, .content ul').each(function(){
            let curList = $(this);
            if(curList.parents("li").length){
                if(curList.parents('.Opened').length||curList.hasClass('Opened')){
                    curList.before(" <img class='icon' src = '/webPics/chevron-circle-down.svg'/>");
                }
                else{
                    curList.before(" <img class='icon' src = '/webPics/chevron-circle-right.svg'/>");
                    curList.slideUp();
                }
            }
        });
        $('.content img[class]').on("click",(el)=>{
            if($(el.target).attr('src') === '/webPics/chevron-circle-down.svg'){
                $(el.target).siblings('ol, ul').slideUp();
                $(el.target).attr('src','/webPics/chevron-circle-right.svg');
            }
            else{
                $(el.target).siblings('ol, ul').slideDown();
                $(el.target).attr('src','/webPics/chevron-circle-down.svg');
            }
        });
        $("img").each(function(){
            this.setAttribute("loading","lazy");
            if(!this.hasAttribute("alt")) {this.setAttribute("alt","");}
            if((!this.classList.contains("icon")) && this.parentElement.tagName==="LI" && $(this).is(':first-child')) {this.parentElement.style.listStyleType = "none";}
        });
        $(".mathStuff, img:not(.icon)").on("click",this.viewImg);
        let h2El = $('h2');
        h2El.on("click",(el)=>{$(el.target).next().slideToggle();});
        $('h3').on("click",(el)=>{$(el.target).nextUntil('h3, br').slideToggle();});
        $("#upButton").on("click",() => {window.scrollTo(0,0)})
        $("#imgViewer").on("click",this.removeViewer);
        $("table").each(function(){
            if(this.parentElement.tagName==="LI"){
                this.parentElement.className = "tableContainer";
                this.parentElement.style.listStyleType = "none";
            }
            else{
                $(this).wrap("<div class='tableContainer'>");
            }
            if(window.getComputedStyle(document.getElementById("bodyId")).minWidth === "100%"){
                this.parentNode.style.marginLeft = "0%";
                this.parentNode.style.marginRight = "0%";
                this.parentNode.style.width = "100%";
                this.style.marginLeft = null;
                this.style.marginRight = null;
                this.style.width = null;
            }
            else{
                this.parentNode.style.marginLeft = this.style.marginLeft;
                this.parentNode.style.marginRight = this.style.marginRight;
                this.parentNode.style.width = this.style.width;
                this.style.marginLeft = null;
                this.style.marginRight = null;
                this.style.width = null;
            }
        })
        window.addEventListener('scroll', this.scrollFunc);
        window.MathJax.typeset();
        $("h3+ul").each(function(){this.previousElementSibling.style.backgroundColor= "rgba(0,0,0,0.05)";});
        fetch("/pages"+window.location.pathname+".html", {method: "HEAD"}).then(r => {
            return new Date(r.headers.get('Last-Modified'));
        }).then((dateRes)=>{
            $(document.querySelector('h1')).after("<div id=\"date\"><b>Last Edit:</b> "+dateRes+"</div><h4>Contents:</h4><ol id='reference'></ol>");
            h2El.each(function(){
                $(document.getElementById("reference")).append("<li><a href='#"+$(this).attr('id')+"'>"+$(this).text()+"</a></li>");
            });
            setTimeout(()=>{
                Article.loadingEl.fadeOut(1000);
                $("body").css("overflow","visible");
                document.querySelector("meta[name=viewport]").setAttribute('content', 'width=device-width, user-scalable=no, initial-scale='+(1/window.devicePixelRatio)+'');
            },1000);
        });
    }

    componentWillUnmount() {
        Article.loadingEl.css("display","block");
        window.removeEventListener('scroll', this.scrollFunc);
        document.body.classList.remove("articleBody");
    }
}

export default Article;