import { useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import "./Worksheet.scss";
import $ from 'jquery';

function Worksheet ()  {

    const [searchParams] = useSearchParams();
    const questionsAndAnswers = require("./pages/"+searchParams.get("topic")+"_worksheet.js");

    useEffect(() => {
        window.scrollTo(0,0);
        let mainEl = $("#main");
        mainEl.addClass("mainToWorkSheet");
        document.getElementById("bodyId").className = "bodyToWorkSheet";
        mainEl.append(<questionsAndAnswers/>);
        $("#loading").fadeOut();
        return ()=>{
            document.getElementById("main").classList.remove("mainToWorkSheet");
            document.getElementById("bodyId").classList.remove("bodyToWorkSheet");
        };
    }, []);

    return (
        <>
            <h1>{searchParams.get("topic").slice(searchParams.get("topic").indexOf("/")+1).replace("_"," ")}</h1>
            <div style={{display:"grid",gridTemplateColumns: "30% 30% 20% 20%"}}>
                <p>First Name: ___________________</p>
                <p>Last Name: ___________________</p>
                <p>ID: ________________</p>
                <p>Date: ___/___/___</p>
            </div>
            {questionsAndAnswers.worksheetQA()}
        </>
    );
}

export default Worksheet;